    "roles": [
      {
        "source": "謝仕榮先生",
        "target": "Mr. Tse Sze-wing",
        "role": "Independent Non-Executive Chairman"
      }
    ],
    "terms": [
      {
        "source": "2019冠狀病毒病",
        "target": "COVID-19"
      }
    ],
    "style_rules": [
      "Use US$ for U.S. dollar amounts.",
      "Keep listed-company annual report disclosure tone formal and publishable.",
      "Do not change numbers, percentages, years, named entities or financial metric values.",
      "Use established financial abbreviations for table labels when provided.",
      "Keep row and column semantics unchanged.",
      "Use n/m for 無意義."
    ]
  },
  "current_unit": {
    "page_no": 10,
    "unit_id": "p10_g03",
    "unit_mode": "semantic_group",
    "slot_count": 6,
    "source_text": "友邦保險在亞洲歷史悠久，源遠流長，經歷各種社會動盪和不明朗時期仍能妥善管理業務，因而贏得卓著的\n聲譽，體現友邦保險誠可信賴、強韌穩健，並堅持為持分者做對的事。自2020年初以來，2019冠狀病毒病大流\n行導致營商環境不斷變化及日趨複雜，而政治、宏觀經濟及資本市場亦出現前所未見的轉移。在這樣的環境下，\n友邦保險的財務實力，以及「幫助大眾活出健康、長久、好生活」的目標，更具重大意義。本人衷心感謝友邦\n保險所有員工、代理和合作夥伴，即使面對最嚴峻的挑戰，他們仍關懷社區，克盡己職，專心致志地為客戶、\n其家庭以及我們的社區提供支援。",
    "current_translation": "AIA has a long and storied history in Asia. Through various periods of social upheaval and uncertainty, the Company has managed its business prudently and earned a distinguished reputation, demonstrating that AIA is trustworthy, resilient and steadfast in doing the right thing for our stakeholders. Since the beginning of 2020, the COVID-19 pandemic has created a constantly evolving and increasingly complex business environment, with unprecedented shifts in the political, macroeconomic and capital market landscapes. In such an environment, AIA's financial strength and our purpose of helping people live healthier, longer, better lives take on even greater significance. I am deeply grateful to all AIA employees, agents and partners who, despite facing the most severe challenges, continue to care for their communities, fulfill their responsibilities and dedicate themselves to supporting our customers, their families and our communities."
  },
  "output_format": {
    "translations": [
      {
        "unit_id": "p10_g03",
        "translation": "<更紧凑译文>"
      }
    ]
  }
}

